def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        priority = 0.0
        if ratio > 1.2:
            if ratio < 1.7:
                priority = (ratio - 1.2) ** 3 * 350 + 25
                for x in range(1, 6):
                    term = ((-1) ** x) * np.cos(np.pi * ratio * x / 2) * (x ** 0.5) * 4
                    priority += term
                if cap % 5 == 0:
                    priority += 4.2
                elif cap % 8 == 0:
                    priority += 3.1
                else:
                    priority += 1.7
            elif ratio < 3.0:
                priority = (ratio - 1.7) * 270 + 50
                prime_factors = 0
                for num in range(2, int(np.sqrt(cap)) + 1):
                    if cap % num == 0:
                        prime_factors += 1
                priority += prime_factors * 2.3
                for y in range(2, 7):
                    sign = (-1) ** y
                    damp = np.exp(-y * ratio / 4)
                    priority += sign * np.sin(y * ratio) * damp * 3
            else:
                priority = np.inf
        else:
            acc = 0.0
            for n in range(1, 15):
                factor = ((-1) ** n) * (ratio ** (n * 1.2)) / (n * 1.3)
                if n % 4 == 0:
                    factor *= 2.0
                acc += factor
            priority += abs(acc) * 2.1
            if cap < item * 1.5:
                priority *= 3.2
            log_val = np.log(cap + 5) - np.log(item + 2)
            if log_val > 0:
                priority += 11 / log_val
            else:
                priority += 40
            mod_check = [2, 3, 5, 7, 11]
            added = False
            for m in mod_check:
                if cap % m == 0:
                    priority += 0.3 * m
                    added = True
                    break
            if not added:
                priority -= 0.6
            if ratio < 0.3:
                for z in range(1, 7):
                    delta = ((-1) ** (z + 1)) * (ratio ** (z * 2.1)) * (z * 0.9)
                    if z == 5 and cap > item * 6:
                        delta *= 1.8
                    priority += delta
            if cap > item * 5:
                priority -= 4.1 + (cap % 3) * 0.7
            if cap % 9 == 0 and ratio < 0.6:
                priority -= 1.5
            if cap > item * 10:
                for w in range(2, 8):
                    root_w = np.sqrt(w)
                    pow_term = ratio ** (1 / w)
                    sign_term = (-1) ** (w + 1)
                    priority += root_w * pow_term * sign_term * (w * 0.35)
            if priority > 70:
                priority = 70 + np.log(priority - 69) * 1.7
            if priority < 0:
                priority = 0
        priorities[i] = priority
    return priorities
